import{_ as t,o as n,c as a,a2 as e}from"./chunks/framework.B72_uj9U.js";const d=JSON.parse('{"title":"Streaming Protocol","description":"How Server-Sent Events deliver incremental LLM responses and why streaming is essential for responsive agent interfaces.","frontmatter":{"title":"Streaming Protocol","description":"How Server-Sent Events deliver incremental LLM responses and why streaming is essential for responsive agent interfaces."},"headers":[],"relativePath":"learn/linear/03-understanding-llms/10-streaming-protocol.md","filePath":"learn/linear/03-understanding-llms/10-streaming-protocol.md"}'),o={name:"learn/linear/03-understanding-llms/10-streaming-protocol.md"};function l(p,s,c,r,i,u){return n(),a("div",null,[...s[0]||(s[0]=[e(`<h1 id="streaming-protocol" tabindex="-1">Streaming Protocol <a class="header-anchor" href="#streaming-protocol" aria-label="Permalink to &quot;Streaming Protocol&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How SSE-based streaming delivers tokens incrementally and the event types you need to handle</li><li>Why streaming is critical for agent UX and how to detect tool calls within a streamed response</li><li>How to implement a streaming parser that accumulates text and identifies complete tool use blocks</li></ul></blockquote><p>When you make a non-streaming API call, you wait for the model to finish generating its entire response before you receive anything. For a response that takes 10 seconds to generate, your user stares at a blank screen for 10 seconds. Streaming fixes this by delivering tokens as they are generated, typically starting within a few hundred milliseconds. For a coding agent that might generate lengthy code or reasoning, streaming is not a nice-to-have -- it is essential for a usable interface.</p><h2 id="server-sent-events-sse" tabindex="-1">Server-Sent Events (SSE) <a class="header-anchor" href="#server-sent-events-sse" aria-label="Permalink to &quot;Server-Sent Events (SSE)&quot;">​</a></h2><p>Both Anthropic and OpenAI use the <strong>Server-Sent Events</strong> protocol for streaming. SSE is a simple HTTP-based protocol where the server sends a stream of events over a long-lived HTTP connection. Each event is a text line prefixed with <code>data: </code>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>data: {&quot;type&quot;: &quot;content_block_start&quot;, ...}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>data: {&quot;type&quot;: &quot;content_block_delta&quot;, ...}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>data: {&quot;type&quot;: &quot;content_block_delta&quot;, ...}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>data: {&quot;type&quot;: &quot;message_stop&quot;}</span></span></code></pre></div><p>Key characteristics of SSE:</p><ul><li>It uses a regular HTTP POST request with <code>&quot;stream&quot;: true</code> in the body</li><li>The response has <code>Content-Type: text/event-stream</code></li><li>Events are separated by blank lines</li><li>The stream ends with a special termination event</li><li>Each <code>data:</code> line contains a complete JSON object</li></ul><p>To enable streaming, you add <code>&quot;stream&quot;: true</code> to your API request:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">model</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;claude-sonnet-4-20250514&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">max_tokens</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;"> 4096</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">stream</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;"> true</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">messages</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#9399B2;">    {</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;user&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Write a Rust function to sort a vector&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">  ]</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><h2 id="anthropic-streaming-events" tabindex="-1">Anthropic Streaming Events <a class="header-anchor" href="#anthropic-streaming-events" aria-label="Permalink to &quot;Anthropic Streaming Events&quot;">​</a></h2><p>Anthropic&#39;s streaming API sends a sequence of typed events. Here is the complete event flow for a response that contains text:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>event: message_start</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;message_start&quot;,&quot;message&quot;:{&quot;id&quot;:&quot;msg_01XFD...&quot;,&quot;type&quot;:&quot;message&quot;,&quot;role&quot;:&quot;assistant&quot;,&quot;content&quot;:[],&quot;model&quot;:&quot;claude-sonnet-4-20250514&quot;,&quot;stop_reason&quot;:null,&quot;usage&quot;:{&quot;input_tokens&quot;:25,&quot;output_tokens&quot;:1}}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>event: content_block_start</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;content_block_start&quot;,&quot;index&quot;:0,&quot;content_block&quot;:{&quot;type&quot;:&quot;text&quot;,&quot;text&quot;:&quot;&quot;}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>event: content_block_delta</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;content_block_delta&quot;,&quot;index&quot;:0,&quot;delta&quot;:{&quot;type&quot;:&quot;text_delta&quot;,&quot;text&quot;:&quot;Here&quot;}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>event: content_block_delta</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;content_block_delta&quot;,&quot;index&quot;:0,&quot;delta&quot;:{&quot;type&quot;:&quot;text_delta&quot;,&quot;text&quot;:&quot;&#39;s a&quot;}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>event: content_block_delta</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;content_block_delta&quot;,&quot;index&quot;:0,&quot;delta&quot;:{&quot;type&quot;:&quot;text_delta&quot;,&quot;text&quot;:&quot; sorting&quot;}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>event: content_block_delta</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;content_block_delta&quot;,&quot;index&quot;:0,&quot;delta&quot;:{&quot;type&quot;:&quot;text_delta&quot;,&quot;text&quot;:&quot; function&quot;}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>event: content_block_stop</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;content_block_stop&quot;,&quot;index&quot;:0}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>event: message_delta</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;message_delta&quot;,&quot;delta&quot;:{&quot;stop_reason&quot;:&quot;end_turn&quot;},&quot;usage&quot;:{&quot;output_tokens&quot;:15}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>event: message_stop</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;message_stop&quot;}</span></span></code></pre></div><p>The event types form a clear hierarchy:</p><table tabindex="0"><thead><tr><th>Event</th><th>Purpose</th></tr></thead><tbody><tr><td><code>message_start</code></td><td>Begins the response, includes model info and input token count</td></tr><tr><td><code>content_block_start</code></td><td>Begins a content block (text or tool_use), includes the block type</td></tr><tr><td><code>content_block_delta</code></td><td>Delivers incremental content within a block</td></tr><tr><td><code>content_block_stop</code></td><td>Ends the current content block</td></tr><tr><td><code>message_delta</code></td><td>Delivers final message metadata including stop_reason and output token count</td></tr><tr><td><code>message_stop</code></td><td>Terminates the stream</td></tr></tbody></table><h2 id="streaming-tool-use-events" tabindex="-1">Streaming Tool Use Events <a class="header-anchor" href="#streaming-tool-use-events" aria-label="Permalink to &quot;Streaming Tool Use Events&quot;">​</a></h2><p>When the model makes a tool call, the streaming events include tool use blocks. This is where streaming gets more complex for agents:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>event: content_block_start</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;content_block_start&quot;,&quot;index&quot;:0,&quot;content_block&quot;:{&quot;type&quot;:&quot;text&quot;,&quot;text&quot;:&quot;&quot;}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>event: content_block_delta</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;content_block_delta&quot;,&quot;index&quot;:0,&quot;delta&quot;:{&quot;type&quot;:&quot;text_delta&quot;,&quot;text&quot;:&quot;Let me read that file.&quot;}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>event: content_block_stop</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;content_block_stop&quot;,&quot;index&quot;:0}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>event: content_block_start</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;content_block_start&quot;,&quot;index&quot;:1,&quot;content_block&quot;:{&quot;type&quot;:&quot;tool_use&quot;,&quot;id&quot;:&quot;toolu_01ABC&quot;,&quot;name&quot;:&quot;read_file&quot;}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>event: content_block_delta</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;content_block_delta&quot;,&quot;index&quot;:1,&quot;delta&quot;:{&quot;type&quot;:&quot;input_json_delta&quot;,&quot;partial_json&quot;:&quot;{\\&quot;pa&quot;}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>event: content_block_delta</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;content_block_delta&quot;,&quot;index&quot;:1,&quot;delta&quot;:{&quot;type&quot;:&quot;input_json_delta&quot;,&quot;partial_json&quot;:&quot;th\\&quot;: \\&quot;sr&quot;}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>event: content_block_delta</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;content_block_delta&quot;,&quot;index&quot;:1,&quot;delta&quot;:{&quot;type&quot;:&quot;input_json_delta&quot;,&quot;partial_json&quot;:&quot;c/main.rs\\&quot;}&quot;}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>event: content_block_stop</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;content_block_stop&quot;,&quot;index&quot;:1}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>event: message_delta</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;message_delta&quot;,&quot;delta&quot;:{&quot;stop_reason&quot;:&quot;tool_use&quot;},&quot;usage&quot;:{&quot;output_tokens&quot;:42}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>event: message_stop</span></span>
<span class="line"><span>data: {&quot;type&quot;:&quot;message_stop&quot;}</span></span></code></pre></div><p>Notice the key difference: tool use blocks stream <code>input_json_delta</code> events containing partial JSON fragments. You cannot parse the tool call arguments until the entire block is complete -- the fragments <code>{&quot;pa</code>, <code>th&quot;: &quot;sr</code>, and <code>c/main.rs&quot;}</code> only form valid JSON when concatenated: <code>{&quot;path&quot;: &quot;src/main.rs&quot;}</code>.</p><h2 id="building-a-streaming-accumulator" tabindex="-1">Building a Streaming Accumulator <a class="header-anchor" href="#building-a-streaming-accumulator" aria-label="Permalink to &quot;Building a Streaming Accumulator&quot;">​</a></h2><p>Your agent needs a streaming parser that accumulates events and produces complete messages. Here is the conceptual structure:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">struct</span><span style="color:#F9E2AF;font-style:italic;"> StreamAccumulator</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    content_blocks</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">ContentBlock</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    current_text</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    current_tool_json</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    current_block_index</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">usize</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    stop_reason</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    input_tokens</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> u32</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    output_tokens</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> u32</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">impl</span><span style="color:#F9E2AF;font-style:italic;"> StreamAccumulator</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    fn</span><span style="color:#89B4FA;font-style:italic;"> process_event</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CBA6F7;">mut</span><span style="color:#F38BA8;"> self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> event</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">StreamEvent</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        match</span><span style="color:#CDD6F4;"> event </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            StreamEvent</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">ContentBlockStart</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> index</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> content_block </span><span style="color:#9399B2;">}</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F38BA8;">                self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">current_block_index </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> Some</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">*</span><span style="color:#CDD6F4;">index</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#CBA6F7;">                match</span><span style="color:#CDD6F4;"> content_block</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">block_type</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">as_str</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#A6E3A1;">                    &quot;text&quot;</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F38BA8;"> self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">current_text</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">clear</span><span style="color:#9399B2;">(),</span></span>
<span class="line"><span style="color:#A6E3A1;">                    &quot;tool_use&quot;</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F38BA8;"> self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">current_tool_json</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">clear</span><span style="color:#9399B2;">(),</span></span>
<span class="line"><span style="color:#CDD6F4;">                    _ </span><span style="color:#94E2D5;">=&gt;</span><span style="color:#9399B2;"> {}</span></span>
<span class="line"><span style="color:#9399B2;">                }</span></span>
<span class="line"><span style="color:#9399B2;">            }</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            StreamEvent</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">ContentBlockDelta</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> index</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> delta </span><span style="color:#9399B2;">}</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">                match</span><span style="color:#CDD6F4;"> delta </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">                    Delta</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">TextDelta</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> text </span><span style="color:#9399B2;">}</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F38BA8;">                        self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">current_text</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push_str</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">text</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">                        // Emit text to UI immediately for display</span></span>
<span class="line"><span style="color:#9399B2;">                    }</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">                    Delta</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">InputJsonDelta</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> partial_json </span><span style="color:#9399B2;">}</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F38BA8;">                        self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">current_tool_json</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push_str</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">partial_json</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">                        // Do NOT try to parse yet - wait for block_stop</span></span>
<span class="line"><span style="color:#9399B2;">                    }</span></span>
<span class="line"><span style="color:#9399B2;">                }</span></span>
<span class="line"><span style="color:#9399B2;">            }</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            StreamEvent</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">ContentBlockStop</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> index </span><span style="color:#9399B2;">}</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">                // Now the block is complete - finalize it</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">                // Parse accumulated JSON for tool calls</span></span>
<span class="line"><span style="color:#9399B2;">            }</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            StreamEvent</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">MessageDelta</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> delta</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> usage </span><span style="color:#9399B2;">}</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F38BA8;">                self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">stop_reason </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> Some</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">delta</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">stop_reason</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">clone</span><span style="color:#9399B2;">());</span></span>
<span class="line"><span style="color:#F38BA8;">                self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">output_tokens </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> usage</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">output_tokens</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#9399B2;">            }</span></span>
<span class="line"><span style="color:#CDD6F4;">            _ </span><span style="color:#94E2D5;">=&gt;</span><span style="color:#9399B2;"> {}</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The critical insight is: <strong>display text deltas immediately, but accumulate tool call JSON until the block is complete</strong>. Text can be streamed to the user character by character. Tool call arguments must be fully accumulated and parsed as complete JSON before you can execute the tool.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>In Python, you consume SSE streams with a <code>for</code> loop over the response: <code>for event in client.messages.stream(...)</code>. The Anthropic and OpenAI Python SDKs handle SSE parsing internally. In Rust, you will use a library like <code>reqwest</code> with streaming response support and parse SSE events manually or with an <code>eventsource</code> crate. The Rust approach gives you zero-copy parsing and explicit control over buffering, but requires more setup code.</p></div><h2 id="openai-streaming-format" tabindex="-1">OpenAI Streaming Format <a class="header-anchor" href="#openai-streaming-format" aria-label="Permalink to &quot;OpenAI Streaming Format&quot;">​</a></h2><p>OpenAI&#39;s streaming format uses a similar SSE transport but different event structure:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>data: {&quot;id&quot;:&quot;chatcmpl-abc&quot;,&quot;object&quot;:&quot;chat.completion.chunk&quot;,&quot;choices&quot;:[{&quot;index&quot;:0,&quot;delta&quot;:{&quot;role&quot;:&quot;assistant&quot;,&quot;content&quot;:&quot;&quot;},&quot;finish_reason&quot;:null}]}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>data: {&quot;id&quot;:&quot;chatcmpl-abc&quot;,&quot;object&quot;:&quot;chat.completion.chunk&quot;,&quot;choices&quot;:[{&quot;index&quot;:0,&quot;delta&quot;:{&quot;content&quot;:&quot;Here&quot;},&quot;finish_reason&quot;:null}]}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>data: {&quot;id&quot;:&quot;chatcmpl-abc&quot;,&quot;object&quot;:&quot;chat.completion.chunk&quot;,&quot;choices&quot;:[{&quot;index&quot;:0,&quot;delta&quot;:{&quot;content&quot;:&quot;&#39;s&quot;},&quot;finish_reason&quot;:null}]}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>data: {&quot;id&quot;:&quot;chatcmpl-abc&quot;,&quot;object&quot;:&quot;chat.completion.chunk&quot;,&quot;choices&quot;:[{&quot;index&quot;:0,&quot;delta&quot;:{&quot;content&quot;:&quot; a sorting function&quot;},&quot;finish_reason&quot;:null}]}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>data: {&quot;id&quot;:&quot;chatcmpl-abc&quot;,&quot;object&quot;:&quot;chat.completion.chunk&quot;,&quot;choices&quot;:[{&quot;index&quot;:0,&quot;delta&quot;:{},&quot;finish_reason&quot;:&quot;stop&quot;}]}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>data: [DONE]</span></span></code></pre></div><p>Key differences from Anthropic:</p><ul><li>No typed event names -- all events are <code>data:</code> lines with JSON</li><li>Content is nested under <code>choices[0].delta</code></li><li>Text appears in <code>delta.content</code></li><li>Tool calls appear in <code>delta.tool_calls</code> as incremental fragments</li><li>Stream ends with <code>data: [DONE]</code> instead of a <code>message_stop</code> event</li><li><code>finish_reason</code> replaces <code>stop_reason</code></li></ul><p>For tool calls in OpenAI&#39;s streaming format:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>data: {&quot;choices&quot;:[{&quot;delta&quot;:{&quot;tool_calls&quot;:[{&quot;index&quot;:0,&quot;id&quot;:&quot;call_abc&quot;,&quot;type&quot;:&quot;function&quot;,&quot;function&quot;:{&quot;name&quot;:&quot;read_file&quot;,&quot;arguments&quot;:&quot;&quot;}}]}}]}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>data: {&quot;choices&quot;:[{&quot;delta&quot;:{&quot;tool_calls&quot;:[{&quot;index&quot;:0,&quot;function&quot;:{&quot;arguments&quot;:&quot;{\\&quot;pa&quot;}}]}}]}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>data: {&quot;choices&quot;:[{&quot;delta&quot;:{&quot;tool_calls&quot;:[{&quot;index&quot;:0,&quot;function&quot;:{&quot;arguments&quot;:&quot;th\\&quot;:&quot;}}]}}]}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>data: {&quot;choices&quot;:[{&quot;delta&quot;:{&quot;tool_calls&quot;:[{&quot;index&quot;:0,&quot;function&quot;:{&quot;arguments&quot;:&quot; \\&quot;src/main.rs\\&quot;}&quot;}}]}}]}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>data: {&quot;choices&quot;:[{&quot;delta&quot;:{},&quot;finish_reason&quot;:&quot;tool_calls&quot;}]}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>data: [DONE]</span></span></code></pre></div><p>The same principle applies: accumulate <code>arguments</code> fragments until the stream ends, then parse the complete JSON.</p><h2 id="why-streaming-matters-for-agents" tabindex="-1">Why Streaming Matters for Agents <a class="header-anchor" href="#why-streaming-matters-for-agents" aria-label="Permalink to &quot;Why Streaming Matters for Agents&quot;">​</a></h2><p>Beyond UX responsiveness, streaming provides functional benefits for agents:</p><p><strong>Early text display:</strong> The model often explains what it is about to do before making a tool call. Streaming lets the user see &quot;Let me read the file to understand the issue...&quot; while the tool call JSON is still being generated.</p><p><strong>Progress indication:</strong> During long responses (like generating a large function), streaming shows the user that work is happening, preventing them from assuming the agent is stuck.</p><p><strong>Cancellation:</strong> With streaming, the user can cancel a response mid-generation if they see the model going in the wrong direction. Without streaming, they would have to wait for the full response.</p><p><strong>Latency hiding:</strong> The time between the first token and the last token is perceived differently than waiting for the entire response. A 10-second generation that starts streaming after 200ms feels much faster than a 10-second wait followed by a full response.</p><h2 id="handling-stream-errors" tabindex="-1">Handling Stream Errors <a class="header-anchor" href="#handling-stream-errors" aria-label="Permalink to &quot;Handling Stream Errors&quot;">​</a></h2><p>Streams can fail mid-response due to network issues, rate limits, or server errors. Your agent needs to handle:</p><p><strong>Connection drops:</strong> The TCP connection closes unexpectedly. Retry the entire request.</p><p><strong>Incomplete JSON:</strong> If the stream ends before <code>message_stop</code>, you may have accumulated partial content. Text content that was already displayed to the user should be preserved, but incomplete tool calls cannot be executed.</p><p><strong>Rate limit errors:</strong> Even streaming responses can hit rate limits. The server might send an error event mid-stream or close the connection with an HTTP error.</p><p>A robust streaming implementation uses timeouts to detect stalled streams (no events for 30+ seconds) and implements retry logic for transient failures.</p><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>Claude Code streams all responses and renders text incrementally in the terminal. Tool calls are shown as &quot;thinking...&quot; until the complete tool call JSON is received, at which point the tool name and arguments are displayed. This approach gives the user continuous feedback about what the agent is doing. The streaming parser maintains a state machine that tracks which content block is currently active, accumulating text and tool call data independently.</p></div><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>SSE streaming delivers tokens incrementally over a long-lived HTTP connection, starting response delivery within hundreds of milliseconds instead of waiting for the complete generation</li><li>Anthropic uses typed events (<code>content_block_start</code>, <code>content_block_delta</code>, <code>content_block_stop</code>) while OpenAI uses a flat <code>data:</code> format with JSON chunks -- both require accumulating tool call JSON until the block completes</li><li>Display text deltas immediately for responsiveness, but accumulate tool call JSON fragments until the content block ends before parsing -- partial JSON is not valid JSON</li><li>Streaming enables cancellation, progress indication, and latency hiding, all of which are critical for agent UX during multi-step operations</li><li>Implement timeout detection and retry logic for stream failures, preserving already-displayed text while discarding incomplete tool calls</li></ul>`,47)])])}const y=t(o,[["render",l]]);export{d as __pageData,y as default};
